sity study visas","Only Canada PR","Driving licence","Tourist visa only"],"correctIndex":0,"explanation":"Universities and most study pathways need Academic.","level":1},{"question":"Counselors must never:","options":["Track mocks","Guarantee band 7","Issue books","Run diagnostic"],"correctIndex":1,"explanation":"Band guarantees are prohibited.","level":1},{"question":"IELTS exam fee in India is paid to:","options":["Future Link only","IDP IELTS India by student","University","Embassy"],"correctIndex":1,"explanation":"Book and pay on ieltsidpindia.com — separate from coaching fee.","level":1},{"question":"Minimum full mocks before exam booking (Regular):","options":["0","4","20","None required"],"correctIndex":1,"explanation":"At least four full mocks under exam conditions.","level":1},{"question":"Attendance below this triggers counselor review:","options":["50%","80%","100%","Never tracked"],"correctIndex":1,"explanation":"Review dips below 80% attendance.","level":1},{"question":"A Canada PR lead needing GT should go to:","options":["Academic Regular","General Regular program","This Academic batch","No coaching"],"correctIndex":1,"explanation":"Do not mix GT students into Academic Regular.","level":2},{"question":"Books in Academic Regular (with books) are:","options":["Optional extra fee","Issued at enrollment","Provided by IDP","Not used"],"correctIndex":1,"explanation":"Issue and log books on Day 1.","level":1},{"question":"Mock readiness rule before IDP booking:","options":["Any single mock","Two mocks within 0.5 of target","No mocks needed","Trainer guess"],"correctIndex":1,"explanation":"Two consecutive mocks near target.","level":2},{"question":"Regular batch typical duration:","options":["1 week","8–10 weeks","12 months","1 day"],"correctIndex":1,"explanation":"Regular pace over 8–10 weeks.","level":1},{"question":"IDP India booking URL:","options":["britishcouncil.in/exam/ielts","ieltsidpindia.com","ielts.org only","futurelinkconsultants.com"],"correctIn