UPDATE public.service_library
SET academy_metadata = '{"displayName":"IELTS Academic Crash Course","shortDescription":"IDP India · Academic module · 4–6 week intensive · Exam deadline focus","version":"v1.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated June 2026","learningLevel":"Advanced","learningMinutes":10,"navBucket":"coaching","policyAlert":{"active":true,"date":"June 2026","summary":"Crash enrollment only when diagnostic gap to target is realistic (typically ≤ 1 band). Book IELTS via ieltsidpindia.com only. Never guarantee a band score."},"alert":{"title":"Intensive pace — not for beginners","body":"Crash suits retakes, near-target students, or hard deadlines. Diagnostic 5.0 → target 7.0 in 4 weeks is not crash-eligible. Academic module only."},"tags":[{"label":"Active program","variant":"success"},{"label":"4–6 weeks","variant":"warning"},{"label":"Intensive","variant":"neutral"},{"label":"Academic module","variant":"warning"}],"chips":[{"label":"Crash batch","variant":"warning"},{"label":"2+ full mocks","variant":"neutral"},{"label":"Deadline-driven","variant":"neutral"},{"label":"Exam fee separate","variant":"neutral"}],"kpis":[{"label":"Course duration","value":"4–6w","sub":"Intensive batch","tone":"primary"},{"label":"IELTS exam fee","value":"See IDP India","sub":"Paid on ieltsidpindia.com","tone":"warning"},{"label":"Target achievement","value":"76%","sub":"Crash-eligible enrollments","tone":"success"},{"label":"Min attendance","value":"85%","sub":"Crash standard","tone":"violet"}],"about":[{"label":"Description","value":"Fast-track IELTS Academic preparation for students with an exam deadline or retake window. Daily classes, heavy homework, focused skill drills, and timed mocks."},{"label":"Ideal for","value":"Retake students within ~0.5–1.0 band of target, conditional offer deadlines, or post-Regular booster needs — not first-time learners far below target."},{"label":"Delivery","value":"Intensive classroom or hybrid. Materials per branch policy. Higher attendance expectation than Regular."},{"label":"Exam authority (India)","value":"IDP IELTS India (ieltsidpindia.com) — sole test booking channel since July 2021. FLC prepares; student registers and pays exam fee separately."},{"label":"After course","value":"Exam booking support, TRF tracking, booster or Regular recommendation if crash timeline insufficient."}],"eligibility":[{"criterion":"Diagnostic shows gap ≤ 1.0 band to agreed target (or skill retake)","met":true},{"criterion":"Exam or university deadline documented","met":true},{"criterion":"Academic module requirement confirmed","met":true},{"criterion":"Student accepts intensive schedule (≥ 85% attendance)","met":true},{"criterion":"Enrollment agreement signed","met":true}],"redFlagsBanner":"If mocks stay far below target mid-crash, pause exam booking — offer Regular extension or realistic retake date.","redFlags":[{"title":"Not crash-eligible","description":"Large band gap or weak foundation.","fix":"Offer Academic Regular instead","severity":"Very common"},{"title":"Missed classes in week 1","description":"Crash pace cannot be recovered.","fix":"Pause or switch to Regular","severity":"Common"},{"title":"GT student in Academic crash","description":"Wrong module.","fix":"Move to GT program","severity":"High"},{"title":"Guaranteed score promised","description":"Compliance breach.","fix":"Never guarantee bands","severity":"High"}],"faqs":[{"q":"Crash vs Regular — when to choose?","a":"Regular for 1.0+ band improvement over 8–10 weeks. Crash when diagnostic is near target and deadline is tight."},{"q":"How many mocks in crash?","a":"Minimum two full mocks; book exam only when latest mock is within 0.5 of target."},{"q":"Who pays exam fee?","a":"Student pays IDP on ieltsidpindia.com — separate from crash course fee."},{"q":"Can we guarantee band 7 in crash?","a":"No. Outcomes depend on starting level, attendance, and exam performance."}],"compliance":["Never guarantee an IELTS band score","Document crash eligibility on enrollment form","Separate coaching fee from IDP exam fee","Record diagnostic and mock scores"],"proTips":["Use crash only after Regular incomplete or retake with clear skill gap","Book IDP slot only after second mock confirms readiness","Brief on test day checklist in final week"],"postApproval":["Collect TRF when released","Update admissions / visa file","Plan retake or OSR if one skill below target"],"performance":{"ourRate":76,"industryRate":62,"stats":[{"label":"Crash enrollments (year)","value":"98"},{"label":"Hit target","value":"74"},{"label":"Extended to Regular","value":"24"}]},"approvalFactors":[{"label":"Attendance 85%+","ours":82,"benchmark":68},{"label":"Mock on schedule","ours":88,"benchmark":70},{"label":"Exam booked when ready","ours":79,"benchmark":65}],"timeline":[{"weeks":"1","title":"Diagnostic, eligibility check, enrollment"},{"weeks":"2–4","title":"Daily classes, drills, weekly speaking mocks"},{"weeks":"3–5","title":"Full mocks & readiness review"},{"weeks":"4–6","title":"IDP booking, test day prep, TRF follow-up"}],"relatedServices":[{"label":"IELTS — Test reference","libraryId":"b2000001-0001-4000-8000-000000000071"},{"label":"IELTS Academic Regular (with books)","libraryId":"b2000001-0001-4000-8000-000000000072"},{"label":"IELTS General Regular (with books)","libraryId":"b2000001-0001-4000-8000-000000000074"}],"changelog":[{"version":"v1.0","date":"June 2026","author":"Service Library","summary":"Initial IELTS Academic Crash coaching specimen."}],"staffNotes":[{"author":"Coaching team","date":"June 2026","text":"Decline crash if gap > 1 band unless skill-specific retake with manager approval."}],"resources":[{"title":"IELTS test reference (FLC specimen)","url":"/specimens/coaching/ielts-test-reference.html","description":"Full test guide"},{"title":"IDP IELTS India — Book test","url":"https://www.ieltsidpindia.com/","description":"Sole booking channel in India"},{"title":"Enrollment checklist — Academic Crash","url":"/specimens/coaching/ielts-academic-crash-checklist.html","description":"Counselor crash enrollment checklist"}],"donts":{"dos":["Verify crash eligibility before quoting","Track daily attendance","Confirm Academic module","Keep exam fee separate"],"donts":["Enroll large band-gap students in crash","Guarantee a band score","Skip mocks before booking","Mix GT leads into Academic crash"],"mistakes":["Diagnostic 5 → target 7 in 4 weeks","Exam booked in week 1","No deadline on file"]},"sampleDocs":[{"title":"Crash eligibility form (mock)","description":"Gap-to-target and deadline sign-off.","docKind":"assessment","mimeType":"application/pdf"}],"quiz":[{"question":"IELTS Academic Crash is best suited when:","options":["Student is 2+ bands below target","Diagnostic gap to target is typically ≤ 1 band","Student needs GT for Canada PR","No exam date exists"],"correctIndex":1,"explanation":"Crash is for near-target or retake students with a deadline.","level":1},{"question":"Minimum attendance standard for crash is approximately:","options":["50%","70%","85%","100%"],"correctIndex":2,"explanation":"Intensive pace requires higher attendance than Regular.","level":1},{"question":"IELTS exam fee in India is paid to:","options":["Future Link only","IDP IELTS India by student","University","Embassy"],"correctIndex":1,"explanation":"Book and pay on ieltsidpindia.com.","level":1},{"question":"Counselors must never:","options":["Track mocks","Guarantee band 7","Confirm module","Share test day checklist"],"correctIndex":1,"explanation":"Band guarantees are prohibited.","level":1},{"question":"Before booking the exam, crash policy recommends:","options":["No mocks","Latest mock within 0.5 of target","Earliest IDP date always","Wait until after test"],"correctIndex":1,"explanation":"Readiness based on mock performance.","level":2},{"question":"A GT student should be enrolled in:","options":["Academic Crash","General Regular or GT crash","PTE only","Spoken English"],"correctIndex":1,"explanation":"Module must match migration or study pathway.","level":1},{"question":"Typical crash duration is:","options":["1 week","4–6 weeks","6 months","1 year"],"correctIndex":1,"explanation":"Intensive 4–6 week batch.","level":1},{"question":"If student misses multiple classes in week 1:","options":["Continue crash unchanged","Pause or switch to Regular","Guarantee target","Skip mocks"],"correctIndex":1,"explanation":"Crash pace cannot be recovered after early absenteeism.","level":2},{"question":"Minimum full mocks in crash course:","options":["0","2","10","20"],"correctIndex":1,"explanation":"At least two full timed mocks.","level":1},{"question":"IDP India became sole IELTS distributor in India in:","options":["2010","July 2021","2024","Never"],"correctIndex":1,"explanation":"Book only on ieltsidpindia.com since July 2021.","level":2}]}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000073';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"IELTS General Regular (with books)","shortDescription":"IDP India · General Training · 8–10 week batch · Books included","version":"v1.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated June 2026","learningLevel":"Intermediate","learningMinutes":12,"navBucket":"coaching","policyAlert":{"active":true,"date":"June 2026","summary":"General Training only — not Academic. Confirm Canada PR / citizenship or other GT pathway before enrollment. Book exam on ieltsidpindia.com. Never guarantee a band score."},"alert":{"title":"General Training module only","body":"Canada Express Entry, citizenship, and many settlement routes require IELTS GT (or Academic where IRCC states). University study requires Academic — do not enroll GT for study visas."},"tags":[{"label":"Active program","variant":"success"},{"label":"Books included","variant":"neutral"},{"label":"8–10 weeks","variant":"neutral"},{"label":"General Training","variant":"warning"}],"chips":[{"label":"Regular batch","variant":"success"},{"label":"Canada PR / CLB","variant":"neutral"},{"label":"GT Reading & Writing","variant":"warning"},{"label":"Exam fee separate","variant":"neutral"}],"kpis":[{"label":"Course duration","value":"8–10w","sub":"Regular GT batch","tone":"primary"},{"label":"IELTS exam fee","value":"See IDP India","sub":"Paid on ieltsidpindia.com","tone":"warning"},{"label":"Target achievement","value":"80%","sub":"Students hitting agreed CLB/band","tone":"success"},{"label":"Enrollment docs","value":"6","sub":"Agreement + pathway note","tone":"violet"}],"about":[{"label":"Description","value":"Structured IELTS General Training preparation — GT Reading & Writing focus, plus Listening and Speaking — with course books, trainer-led classes, and full GT mocks."},{"label":"Ideal for","value":"Canada PR (Express Entry), citizenship, UK settlement, and other migration pathways requiring IELTS GT — not university admission."},{"label":"Delivery","value":"Regular pace over 8–10 weeks. Classroom or hybrid. Books issued at enrollment."},{"label":"Exam authority (India)","value":"IDP IELTS India (ieltsidpindia.com) — sole test booking channel since July 2021. Student selects General Training at registration."},{"label":"After course","value":"TRF handoff to visa team, CLB mapping for Canada files, retake plan if below pathway minimum."}],"eligibility":[{"criterion":"Migration / PR pathway confirmed — GT required (not Academic)","met":true},{"criterion":"Diagnostic or prior GT score on file","met":true},{"criterion":"Realistic CLB / band target vs current level","met":true},{"criterion":"Enrollment agreement signed","met":true},{"criterion":"Course fee collected","met":true}],"redFlagsBanner":"Study-abroad leads needing Academic must not stay in GT batch. Confirm IRCC accepts GT for the specific program before enrollment.","redFlags":[{"title":"University student in GT batch","description":"Study visas need Academic.","fix":"Transfer to Academic Regular","severity":"High"},{"title":"Wrong CLB target quoted","description":"FSW needs CLB 7 = 6.0 each.","fix":"Reconfirm IRCC requirements","severity":"Common"},{"title":"Academic booked at IDP by mistake","description":"Module mismatch on TRF.","fix":"Cancel and rebook GT before test","severity":"High"},{"title":"Guaranteed score promised","description":"Compliance breach.","fix":"Never guarantee bands","severity":"High"}],"faqs":[{"q":"GT vs Academic — quick rule?","a":"Academic for university. GT for most Canada PR/citizenship and many work/settlement routes."},{"q":"CLB 7 for Express Entry equals:","a":"Approximately IELTS 6.0 in each skill (Listening, Reading, Writing, Speaking)."},{"q":"Are books included?","a":"Yes for Regular (with books) — issue at enrollment."},{"q":"Who pays exam fee?","a":"Student pays IDP on ieltsidpindia.com — separate from coaching fee."},{"q":"Is TOEFL accepted for Canada PR?","a":"No. IRCC accepts IELTS GT/Academic (per program) and CELPIP — not TOEFL."}],"compliance":["Never guarantee an IELTS band score","Confirm GT module and pathway before enrollment","Separate coaching fee from IDP exam fee","Record CLB target on Canada files"],"proTips":["Map every Canada lead to CLB before quoting timeline","Use GT letter-writing drills early — Task 1 differs from Academic","Link TRF to Express Entry file as soon as scores arrive"],"postApproval":["Collect TRF with GT confirmation","Notify visa team with CLB breakdown","Plan retake if any skill below minimum"],"performance":{"ourRate":80,"industryRate":65,"stats":[{"label":"GT enrollments (year)","value":"142"},{"label":"Hit CLB / band target","value":"114"},{"label":"Retake / booster","value":"28"}]},"approvalFactors":[{"label":"Pathway confirmed GT","ours":94,"benchmark":78},{"label":"Attendance 80%+","ours":86,"benchmark":72},{"label":"Mock completion","ours":89,"benchmark":74}],"timeline":[{"weeks":"1","title":"Diagnostic, pathway check, enrollment & books"},{"weeks":"2–7","title":"GT classes, letter writing, reading drills"},{"weeks":"6–8","title":"Full GT mocks & readiness review"},{"weeks":"8–10","title":"IDP GT booking, test day, TRF to visa team"}],"relatedServices":[{"label":"IELTS — Test reference","libraryId":"b2000001-0001-4000-8000-000000000071"},{"label":"Canada — Express Entry PR","libraryId":"b2000001-0001-4000-8000-000000000013"},{"label":"IELTS Academic Regular (with books)","libraryId":"b2000001-0001-4000-8000-000000000072"},{"label":"IELTS Academic Crash Course","libraryId":"b2000001-0001-4000-8000-000000000073"}],"changelog":[{"version":"v1.0","date":"June 2026","author":"Service Library","summary":"Initial IELTS General Regular coaching specimen."}],"staffNotes":[{"author":"Coaching team","date":"June 2026","text":"Do not place study-visa Academic inquiries in GT Regular — wrong module and wrong prep."}],"resources":[{"title":"IELTS test reference (FLC specimen)","url":"/specimens/coaching/ielts-test-reference.html","description":"Acceptance matrix — GT vs Academic"},{"title":"IDP IELTS India — Book test","url":"https://www.ieltsidpindia.com/","description":"Select General Training at registration"},{"title":"IRCC — Language requirements","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/express-entry/documents/language-requirements.html","description":"CLB and accepted tests"},{"title":"Enrollment checklist — GT Regular","url":"/specimens/coaching/ielts-gt-regular-checklist.html","description":"Counselor GT enrollment checklist"}],"donts":{"dos":["Confirm GT pathway before enrollment","Map CLB for Canada leads","Issue books Day 1","Keep exam fee separate"],"donts":["Enroll university leads in GT","Guarantee CLB 9","Book Academic exam for GT student","Skip pathway documentation"],"mistakes":["Study visa in GT batch","CLB 7 quoted as 7.0 overall only","Visa team not updated when TRF arrives"]},"sampleDocs":[{"title":"CLB mapping sheet (mock)","description":"IELTS GT score to CLB per skill.","docKind":"assessment","mimeType":"application/pdf"},{"title":"GT Writing Task 1 letter sample (mock)","description":"Formal letter structure for GT.","docKind":"writing_sample","mimeType":"application/pdf"}],"quiz":[{"question":"IELTS General Training is typically required for:","options":["University PhD admission","Canada Express Entry PR","Medical licensing only","Internal FLC diagnostic"],"correctIndex":1,"explanation":"GT is standard for many Canadian immigration pathways.","level":1},{"question":"CLB 7 for Express Entry FSW equals approximately:","options":["IELTS 5.0 each","IELTS 6.0 each","IELTS 7.5 each","IELTS 8.0 each"],"correctIndex":1,"explanation":"CLB 7 maps to 6.0 in each skill.","level":2},{"question":"A student visa applicant should enroll in:","options":["IELTS GT Regular","IELTS Academic Regular","Spoken English only","No IELTS needed"],"correctIndex":1,"explanation":"Universities require Academic module.","level":1},{"question":"GT Writing Task 1 is typically:","options":["Graph description","Letter writing","Multiple choice","Listening only"],"correctIndex":1,"explanation":"GT Task 1 is a letter; Academic Task 1 is a report.","level":1},{"question":"IELTS exam fee in India is paid to:","options":["Future Link","IDP IELTS India by student","IRCC","Embassy"],"correctIndex":1,"explanation":"ieltsidpindia.com — separate from coaching.","level":1},{"question":"Counselors must never:","options":["Document pathway","Guarantee band 8","Track GT mocks","Map CLB"],"correctIndex":1,"explanation":"Band guarantees are prohibited.","level":1},{"question":"TOEFL is accepted by IRCC for Canadian PR:","options":["Yes","No","Only Quebec","Only with LMIA"],"correctIndex":1,"explanation":"IRCC does not accept TOEFL for immigration.","level":2},{"question":"At IDP registration, GT student must select:","options":["Academic","General Training","UKVI only","Any module"],"correctIndex":1,"explanation":"Module must match coaching and visa pathway.","level":1},{"question":"Before exam booking, GT Regular recommends:","options":["Zero mocks","Two mocks within 0.5 of target","Random date","Guaranteed score"],"correctIndex":1,"explanation":"Same readiness standard as Academic Regular.","level":2},{"question":"Books in GT Regular (with books) are:","options":["Never provided","Issued at enrollment","Sold separately always","IDP provides them"],"correctIndex":1,"explanation":"Issue and log books on Day 1.","level":1},{"question":"Listening and Speaking in GT vs Academic:","options":["Completely different tests","Same test content","GT has no Speaking","Academic has no Listening"],"correctIndex":1,"explanation":"L/S are the same; R/W differ.","level":2},{"question":"British Council India role for IELTS exam:","options":["Books all India tests","Prep only — IDP books tests","Issues TRF","Sets CLB scores"],"correctIndex":1,"explanation":"IDP is sole booking channel since July 2021.","level":2}]}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000074';

INSERT INTO public.service_library_checklist_files
  (library_id, file_name, file_path, mime_type, size_bytes, version, is_current, notes)
SELECT
  'b2000001-0001-4000-8000-000000000072'::uuid,
  'IELTS Academic Regular (with books) — Enrollment Checklist.html',
  '/specimens/coaching/ielts-academic-regular-checklist.html',
  'text/html',
  0,
  1,
  true,
  'Coaching enrollment & delivery checklist — Academic Regular'
