  SELECT 1 FROM public.service_library_checklist_files cf
  WHERE cf.library_id = 'b2000001-0001-4000-8000-000000000072'::uuid
    AND cf.file_path = '/specimens/coaching/ielts-academic-regular-checklist.html'
);

